def solve(data):
    if not data or not isinstance(data, list):
        return []

    merged_data = []
    current_value = None
    current_count = 0

    for value in data:
        if value == current_value:
            current_count += 1
        else:
            if current_count > 0:
                merged_data.append(current_value if current_count == 1 else f"{current_value} (merged)")
            current_value = value
            current_count = 1

    if current_count > 0:
        merged_data.append(current_value if current_count == 1 else f"{current_value} (merged)")

    return merged_data
